defmodule DevopsAutomation.CommandService do
  @moduledoc """
  A safe command execution service that only allows predefined,
  allowlisted commands. Never passes raw user input to a shell.
  """

  # Allowlist of permitted commands with their actual executables and fixed args
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "uptime" => {"/usr/bin/uptime", []},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.ID}}\t{{.Names}}\t{{.Status}}"]},
    "service_status" => {"/usr/bin/systemctl", ["status"]},
    "ping" => {"/usr/bin/ping", ["-c", "4"]}
  }

  @doc """
  Executes a predefined command by name with optional safe arguments.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, args \\ []) when is_binary(command_name) and is_list(args) do
    with :ok <- validate_command(command_name),
         :ok <- validate_args(args),
         {:ok, {executable, base_args}} <- get_command(command_name),
         full_args <- base_args ++ sanitize_args(args) do
      try do
        {output, exit_code} =
          System.cmd(executable, full_args,
            stderr_to_stdout: true,
            env: [{"PATH", "/usr/bin:/usr/local/bin"}],
            timeout: 30_000
          )

        case exit_code do
          0 -> {:ok, %{output: output, exit_code: 0}}
          code -> {:error, %{output: output, exit_code: code}}
        end
      rescue
        e in ErlangError ->
          {:error, %{reason: "Command execution failed: #{inspect(e)}"}}
      end
    end
  end

  defp get_command(command_name) do
    case Map.fetch(@allowed_commands, command_name) do
      {:ok, command_tuple} -> {:ok, command_tuple}
      :error -> {:error, %{reason: "Command '#{command_name}' is not in the allowlist"}}
    end
  end

  defp validate_command(command_name) do
    if Map.has_key?(@allowed_commands, command_name) do
      :ok
    else
      {:error, %{reason: "Unknown command: #{command_name}. Allowed: #{inspect(Map.keys(@allowed_commands))}"}}
    end
  end

  defp validate_args(args) do
    if Enum.all?(args, &safe_arg?/1) do
      :ok
    else
      {:error, %{reason: "Arguments contain disallowed characters"}}
    end
  end

  # Only allow alphanumeric, dots, hyphens, underscores, and forward slashes
  defp safe_arg?(arg) when is_binary(arg) do
    Regex.match?(~r/\A[a-zA-Z0-9._\-\/]+\z/, arg)
  end

  defp safe_arg?(_), do: false

  defp sanitize_args(args) do
    Enum.filter(args, &safe_arg?/1)
  end

  def list_available_commands do
    Map.keys(@allowed_commands)
  end
end

defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  # Optional: Add authentication plug
  # plug :require_admin_auth

  def index(conn, _params) do
    json(conn, %{available_commands: CommandService.list_available_commands()})
  end

  def execute(conn, %{"command" => command_name} = params) do
    args = Map.get(params, "args", [])

    args =
      cond do
        is_list(args) -> args
        is_binary(args) -> [args]
        true -> []
      end

    case CommandService.execute(command_name, args) do
      {:ok, result} ->
        conn
        |> put_status(:ok)
        |> json(%{status: "success", data: result})

      {:error, %{reason: reason}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: reason})

      {:error, %{output: output, exit_code: code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", output: output, exit_code: code})
    end
  end

